abstract class Shape {
    String color;

    Shape(String color) {
        this.color = color;
    }

    // Abstract method — subclasses MUST implement this
    abstract double area();

    void describe() {
        System.out.println("Color: " + color + ", Area: " + String.format("%.2f", area()));
    }
}

// Triangle extends Shape: fields base and height, area = 0.5 * base * height

// Square extends Shape: field side, area = side * side

public class AbstractDemo {
    public static void main(String[] args) {
        Shape t = new Triangle("Red", 6.0, 4.0);
        Shape s = new Square("Blue", 5.0);
        t.describe();
        s.describe();
    }
}

interface Printable {
    void print(); // implicitly public and abstract
}

// Document implements Printable: has String title
// print(): prints "Printing document: <title>"

// Photo implements Printable: has String filename, int width, int height
// print(): prints "Printing photo: <filename> (<width>x<height>)"

public class InterfaceDemo {
    public static void main(String[] args) {
        Printable doc = new Document("Annual Report");
        Printable photo = new Photo("vacation.jpg", 1920, 1080);

        doc.print();
        photo.print();
    }
}

interface Flyable {
    void fly();
}

interface Swimmable {
    void swim();
}

// Duck implements both Flyable and Swimmable
// fly(): prints "Duck is flying."
// swim(): prints "Duck is swimming."

// Penguin implements only Swimmable
// swim(): prints "Penguin is swimming."

public class MultiInterface {
    public static void main(String[] args) {
        Duck duck = new Duck();
        duck.fly();
        duck.swim();

        Swimmable penguin = new Penguin();
        penguin.swim();
    }
}
